private Calendar parseCalendar(String value) {
    Date date = Encoder.parseStandardDate(value);
    if (date == null) return null;
    Calendar cal = Calendar.getInstance();
    cal.setTime(date);
    return cal;
}

    private boolean isSameDate(Calendar c1, Calendar c2) {
        if (c1 == null || c2 == null) return false;
        if (c1.get(Calendar.YEAR) == c2.get(Calendar.YEAR) &&
                c1.get(Calendar.MONTH) == c2.get(Calendar.MONTH) &&
                c1.get(Calendar.DAY_OF_MONTH) == c2.get(Calendar.DAY_OF_MONTH)) {
            return true;
        }
        return false;
    }

    private  List<String> getRecentYearsMonthStr(int n){
        List<String> yearMonths = new ArrayList<>();
        Date date = new Date();
        Calendar cal = new GregorianCalendar();
        cal.setTime(date);
        int year = cal.get(Calendar.YEAR);
        int month = cal.get(Calendar.MONTH) + 1;

        int cnt = 0;
        int nowMonth = month;
        while(cnt < n * 12){
            if(cnt == 0){
                yearMonths.add(year +  padMonthWithZero(nowMonth));
            }else{
                if(nowMonth == 0){
                    nowMonth = 12;
                    year = year -1;
                }
                yearMonths.add(year +  padMonthWithZero(nowMonth));
            }

            nowMonth = nowMonth -1;
            cnt++;
        }

        return yearMonths;
    }

    private String padMonthWithZero(int month){
        String returnVal = month + "";
        if(month < 10){
            returnVal = "0" + month;
        }

        return returnVal;
    }

    private boolean isDate(String datestr, SimpleDateFormat sdf){
        boolean isDate = false;
        try{
            Date date = sdf.parse(datestr);
            isDate = true;
        }catch(Exception e){
            isDate = false;
        }
        return isDate;
    }

