    public UserDetail(String email, String name, String status, String internalOrExternal, String groups) {
        this.email = email;
        this.name = name;
        this.status = status;
        this.internalOrExternal = internalOrExternal;
        this.groups = groups;
        this.numOfLoginDays = 0;
        this.loginRecord = new StringBuilder();
        this.lastLoginTime = null;
        this.lastLoginIp = "";
    }
    
    public void setLastLoginIp(String ip) {
        this.lastLoginIp = ip;
    }
    
    public void setLastLoginTime(Calendar c) {
        this.lastLoginTime = c;
    }
    
    public void appendLoginRecord(String line) {
        if (this.loginRecord.length() > 0) {
            this.loginRecord.append("<br>");
        }
        this.loginRecord.append(line);
    }
    
    public void addNumOfLoginDays(int num) {
        this.numOfLoginDays = this.numOfLoginDays + num;
    }
    
    public void addTask(JSONObject task) {
        String status = task.optString("s");
        if (Const.TASK_STATUS_FINISH.equals(status)) {
            this.doneTasks.add(task);
            this.numOfDoneTasks++;
        }
        else if (Const.TASK_STATUS_INPROGRESS.equals(status)) {
            this.undoneTasks.add(task);
            this.numOfUndoneTasks++;
        }
    }
    
    public Calendar getLastLoginTime() {
        return this.lastLoginTime;
    }
    
    public int getNumOfLoginDays() {
        return this.numOfLoginDays;
    }
    
    public String getName() {
        return this.name;
    }
    
    public String getStatus() {
        return this.status;
    }
    
    public String getGroups() {
        return this.groups;
    }
    
    public String getInternalOrExternal(RagicBundle bundle) {
        if ("Internal".equals(this.internalOrExternal)) {
            return bundle.getString("internalUser");
        } else {
            return bundle.getString("externalUser");
        }
    }
    
    public String getLoginRecord() {
        return this.loginRecord.toString();
    }
    
    public String getLastLoginIp() {
        return this.lastLoginIp;
    }

